noncompliant:
// Noncompliant: Logger field is public
public class MyClass
{
    public ILogger logger; // Noncompliant - should be private
}

// Noncompliant: Logger field is not static
public class MyClass
{
    private readonly ILogger logger; // Noncompliant - should be static
}

// Noncompliant: Logger field is not readonly
public class MyClass
{
    private static ILogger logger; // Noncompliant - should be readonly
}

compliant:
// Compliant: Logger field is private, static, and readonly
public class MyClass
{
    private static readonly ILogger logger = LogManager.GetLogger(typeof(MyClass)); // Compliant
}

// Compliant: All modifiers present
public class MyService
{
    private static readonly ILogger<MyService> _logger; // Compliant

    public MyService(ILogger<MyService> logger)
    {
        _logger = logger;
    }
}
